private Node parseContextTypeExpression(JsDocToken token) {
    if (token == null) {
        throw new IllegalArgumentException("Token cannot be null");
    }
    switch (token) {
        case QMARK:
        case STAR:
            return createNodeForSpecialType(token);
        default:
            return parseTypeName(token);
    }
}

private Node createNodeForSpecialType(JsDocToken token) {
    switch (token) {
        case QMARK:
            return new Node(Token.QMARK);
        case STAR:
            return new Node(Token.STAR);
        default:
            throw new IllegalArgumentException("Invalid special token: " + token);
    }
}
